class _sfxinfo_t:
    def __init__(self, t):
        self.name = t[0] if len(t) > 0 else None
        self.singularity = t[1] if len(t) > 1 else False
        self.priority = t[2] if len(t) > 2 else 0
        self.link = t[3] if len(t) > 3 else None
        self.pitch = t[4] if len(t) > 4 else -1
        self.volume = t[5] if len(t) > 5 else -1
        self.data = t[6] if len(t) > 6 else None
        self.usefulness = t[7] if len(t) > 7 else 0
        self.lumpnum = t[8] if len(t) > 8 else -1

if 'S_sfx' in globals() and len(S_sfx) > 0 and isinstance(S_sfx[0], tuple):
    S_sfx = [_sfxinfo_t(x) for x in S_sfx]

class _musicinfo_t:
    def __init__(self, t):
        self.name = t[0] if len(t) > 0 else None
        self.lumpnum = t[1] if len(t) > 1 else -1
        self.data = t[2] if len(t) > 2 else None
        self.handle = t[3] if len(t) > 3 else None

if 'S_music' in globals() and len(S_music) > 0 and isinstance(S_music[0], tuple):
    S_music = [_musicinfo_t(x) for x in S_music]
